{
var seed = GetInt(parameters, "seed", context.Seed);
var time = GetFloat(parameters, "time", 0f);
var density = GetFloat(parameters, "density", 0.4f);
var height = GetFloat(parameters, "height", 0.3f);
var flowSpeed = GetFloat(parameters, "flowSpeed", 0.3f);
var windDir = GetFloat(parameters, "windDirection", 0f);
var contrast = GetFloat(parameters, "contrast", 0.5f);
var pixelSize = Math.Max(1, GetInt(parameters, "pixelSize", 1));
var color = GetColor(parameters, "color", System.Windows.Media.Color.FromRgb(200, 210, 220));

var cR = color.R/255f; var cG = color.G/255f; var cB = color.B/255f;
var size = context.TileSize;
var result = new PixelBuffer(size, size);

// Time-driven horizontal scroll for flowing fog
var timeOffsetX = time * flowSpeed * 3f;
var timeOffsetY = time * flowSpeed * 1.2f;
var windOffX = windDir * 0.5f;

var scale = 2.0f;
var period = Math.Max(1, (int)(size * scale));

result.ParallelForEachPixel((x, y) =>
{
    var u = x / (float)size * scale + timeOffsetX + windOffX;
    var v = y / (float)size * scale + timeOffsetY;

    // Layered noise for organic mist
    var n1 = TileableFractalNoise(u, v, period, 4, 0.55f, 2f, seed);
    var n2 = TileableFractalNoise(u * 2.3f + 10f, v * 2.3f + 10f, period, 3, 0.5f, 2.2f, seed + 500);
    var n = (n1 * 0.6f + n2 * 0.4f);

    // Apply contrast
    n = MathF.Pow(n, 1f + (1f - contrast) * 2f);

    // Height gradient: fog denser at bottom
    var yFrac = y / (float)size;
    var heightMask = Math.Clamp((height * 2f - yFrac) / Math.Max(0.01f, height * 2f), 0f, 1f);
    heightMask = heightMask * heightMask * (2f - heightMask);

    // Wispy detail: add some vertical variation
    var wisp = MathF.Sin(u * 5f + v * 3f) * 0.5f + 0.5f;
    var wispMask = 0.7f + wisp * 0.3f;

    var alpha = Math.Clamp(n * density * heightMask * wispMask, 0f, 1f);
    result.SetPixel(x, y, cR, cG, cB, alpha);
});
return result;
}
